import test from "node:test";
import assert from "node:assert/strict";
import { crawl, type CrawlPage } from "../../lib/site-crawler.ts";
import type { SiteCrawlConfig } from "../../lib/site-types.ts";

interface FakeNode { url: string; status: number; links: string[]; }

function makePage(nodes: Record<string, FakeNode>): CrawlPage {
  let current: FakeNode | null = null;
  return {
    async goto(url) {
      const node = nodes[url];
      current = node ?? null;
      return node ? { status: () => node.status, url: () => node.url } : null;
    },
    async getLinks() { return current ? current.links : []; },
    url() { return current?.url ?? "about:blank"; },
  };
}

const baseCfg: SiteCrawlConfig = {
  startUrls: ["https://a.com/"], maxDepth: 2, maxPages: 10, allowSubdomains: false,
};

test("visits start url at depth 0", async () => {
  const page = makePage({ "https://a.com/": { url: "https://a.com/", status: 200, links: [] } });
  const out = await crawl(page, baseCfg);
  assert.equal(out.visited.length, 1);
});

test("follows same-origin links up to maxDepth", async () => {
  const page = makePage({
    "https://a.com/": { url: "https://a.com/", status: 200, links: ["/x", "/y"] },
    "https://a.com/x": { url: "https://a.com/x", status: 200, links: ["/z"] },
    "https://a.com/y": { url: "https://a.com/y", status: 200, links: [] },
    "https://a.com/z": { url: "https://a.com/z", status: 200, links: [] },
  });
  const out = await crawl(page, { ...baseCfg, maxDepth: 1 });
  const urls = out.visited.map((v) => v.url).sort();
  assert.deepEqual(urls, ["https://a.com/", "https://a.com/x", "https://a.com/y"]);
});

test("rejects external origin", async () => {
  const page = makePage({
    "https://a.com/": { url: "https://a.com/", status: 200, links: ["https://b.com/x"] },
  });
  const out = await crawl(page, baseCfg);
  assert.equal(out.visited.length, 1);
  assert.ok(out.skipped.some((s) => s.reason === "external"));
});

test("respects excludePatterns", async () => {
  const page = makePage({
    "https://a.com/": { url: "https://a.com/", status: 200, links: ["/admin/danger", "/safe"] },
    "https://a.com/safe": { url: "https://a.com/safe", status: 200, links: [] },
  });
  const out = await crawl(page, { ...baseCfg, excludePatterns: ["/admin/"] });
  const urls = out.visited.map((v) => v.url).sort();
  assert.deepEqual(urls, ["https://a.com/", "https://a.com/safe"]);
});

test("respects maxPages", async () => {
  const page = makePage({
    "https://a.com/": { url: "https://a.com/", status: 200, links: ["/a", "/b", "/c"] },
    "https://a.com/a": { url: "https://a.com/a", status: 200, links: [] },
    "https://a.com/b": { url: "https://a.com/b", status: 200, links: [] },
    "https://a.com/c": { url: "https://a.com/c", status: 200, links: [] },
  });
  const out = await crawl(page, { ...baseCfg, maxPages: 2 });
  assert.equal(out.visited.length, 2);
